<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="sentinel">
            @if (_loading)
            {
                <div class="loading-spinner" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private InfiniteScrollListInterop? _interop;
    private DotNetObjectReference<InfiniteScrollListBase>? _dotNetRef;
    private bool _loading;
    private bool _hasMoreChanged;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override void OnParametersSet()
    {
        _hasMoreChanged = true;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new InfiniteScrollListInterop(JS);
            _dotNetRef = DotNetObjectReference.Create((InfiniteScrollListBase)this);

            if (HasMore)
            {
                await _interop.InitializeAsync(_sentinelRef, _dotNetRef);
            }

            _hasMoreChanged = false;
        }
        else if (_hasMoreChanged && HasMore && _interop is not null && _dotNetRef is not null)
        {
            _hasMoreChanged = false;
            await _interop.InitializeAsync(_sentinelRef, _dotNetRef);
        }
    }

    async ValueTask IAsyncDisposable.DisposeAsync()
    {
        if (_interop is not null)
            await _interop.DisposeAsync();

        _dotNetRef?.Dispose();
    }
}

.infinite-scroll-container {
    overflow-y: auto;
    max-height: 80vh;
}

.sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
    min-height: 1px;
}

.loading-spinner {
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: spin 0.75s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

